import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronUp, ChevronDown, ShoppingCart } from 'lucide-react';
import { foodImages } from '../data/foodImages';

const HeroSection = () => {
  const [activeIndex, setActiveIndex] = useState(0);

  // Handle navigation to previous food item
  const handlePrevious = () => {
    setActiveIndex((prev) => (prev === 0 ? foodImages.length - 1 : prev - 1));
  };

  // Handle navigation to next food item
  const handleNext = () => {
    setActiveIndex((prev) => (prev === foodImages.length - 1 ? 0 : prev + 1));
  };

  // Get surrounding food images for the circular layout
  const getSurroundingImages = () => {
    const surrounding = [];
    for (let i = 1; i <= 3; i++) {
      const prevIndex = (activeIndex - i + foodImages.length) % foodImages.length;
      const nextIndex = (activeIndex + i) % foodImages.length;
      surrounding.push({
        index: prevIndex,
        position: 'top',
        offset: i,
      });
      surrounding.push({
        index: nextIndex,
        position: 'bottom',
        offset: i,
      });
    }
    return surrounding;
  };

  const currentFood = foodImages[activeIndex];
  const surroundingImages = getSurroundingImages();

  // Animation variants
  const imageVariants = {
    enter: {
      opacity: 0,
      scale: 0.8,
      y: 20,
    },
    center: {
      opacity: 1,
      scale: 1,
      y: 0,
      transition: {
        duration: 0.6,
        ease: 'easeInOut',
      },
    },
    exit: {
      opacity: 0,
      scale: 0.8,
      y: -20,
      transition: {
        duration: 0.4,
        ease: 'easeInOut',
      },
    },
  };

  const floatingVariants = {
    animate: {
      y: [0, -10, 0],
      transition: {
        duration: 4,
        repeat: Infinity,
        ease: 'easeInOut',
      },
    },
  };

  const smallImageVariants = {
    initial: {
      opacity: 0,
      scale: 0.6,
    },
    animate: {
      opacity: 0.7,
      scale: 1,
      transition: {
        duration: 0.5,
        ease: 'easeInOut',
      },
    },
    hover: {
      scale: 1.1,
      opacity: 1,
    },
  };

  return (
    <section className="relative min-h-screen bg-gradient-to-br from-green-50 via-white to-green-50 overflow-hidden">
      {/* Navbar */}
      <nav className="fixed top-0 left-0 right-0 z-50 bg-white/80 backdrop-blur-md border-b border-green-100">
        <div className="max-w-7xl mx-auto px-6 py-4 flex items-center justify-between">
          {/* Logo */}
          <motion.div
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.5 }}
            className="text-2xl font-bold text-green-600"
          >
            Food Palace
          </motion.div>

          {/* Menu Items */}
          <motion.div
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.1 }}
            className="hidden md:flex gap-8 items-center"
          >
            {['Breakfast', 'Lunch', 'Dinner'].map((item, index) => (
              <motion.a
                key={item}
                href="#"
                className="text-gray-700 font-medium hover:text-green-600 transition-colors"
                whileHover={{ y: -2 }}
                transition={{ delay: 0.1 * (index + 1) }}
              >
                {item}
              </motion.a>
            ))}
          </motion.div>

          {/* Cart Icon */}
          <motion.button
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.5 }}
            whileHover={{ scale: 1.1 }}
            whileTap={{ scale: 0.95 }}
            className="relative p-2 hover:bg-green-100 rounded-full transition-colors"
          >
            <ShoppingCart className="text-green-600" size={24} />
            <span className="absolute top-1 right-1 w-2 h-2 bg-red-500 rounded-full"></span>
          </motion.button>
        </div>
      </nav>

      {/* Main Hero Content */}
      <div className="pt-24 px-6 pb-12">
        <div className="max-w-7xl mx-auto">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-center min-h-[calc(100vh-120px)]">
            {/* Left Content Section */}
            <motion.div
              initial={{ opacity: 0, x: -50 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.8, ease: 'easeInOut' }}
              className="flex flex-col justify-center"
            >
              {/* Main Heading */}
              <motion.h1
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.8, delay: 0.2 }}
                className="text-5xl md:text-6xl lg:text-7xl font-bold text-gray-900 mb-4 leading-tight"
              >
                Delicious
              </motion.h1>

              {/* Subheading */}
              <motion.h2
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.8, delay: 0.3 }}
                className="text-3xl md:text-4xl lg:text-5xl font-bold text-green-600 mb-6"
              >
                Kill the Hunger
              </motion.h2>

              {/* Description */}
              <motion.p
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.8, delay: 0.4 }}
                className="text-lg text-gray-600 mb-8 leading-relaxed max-w-md"
              >
                Experience premium quality meals crafted with fresh ingredients and delivered straight to your door. Satisfy your cravings with our delicious food selections.
              </motion.p>

              {/* CTA Button */}
              <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.8, delay: 0.5 }}
              >
                <motion.button
                  whileHover={{ scale: 1.05, boxShadow: '0 20px 40px rgba(34, 197, 94, 0.3)' }}
                  whileTap={{ scale: 0.95 }}
                  className="px-8 py-4 bg-green-600 text-white font-bold rounded-full text-lg hover:bg-green-700 transition-colors shadow-lg"
                >
                  Order Now
                </motion.button>
              </motion.div>
            </motion.div>

            {/* Right Food Image Section */}
            <motion.div
              initial={{ opacity: 0, x: 50 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.8, ease: 'easeInOut' }}
              className="relative h-full flex items-center justify-center"
            >
              {/* SVG Dotted Curve Path */}
              <svg
                className="absolute inset-0 w-full h-full"
                viewBox="0 0 400 500"
                preserveAspectRatio="xMidYMid meet"
              >
                <defs>
                  <style>{`
                    .dotted-path {
                      stroke: #d1d5db;
                      stroke-width: 2;
                      stroke-dasharray: 5, 5;
                      fill: none;
                    }
                  `}</style>
                </defs>
                {/* Top curve */}
                <path
                  className="dotted-path"
                  d="M 200 50 Q 100 150 200 250"
                />
                {/* Bottom curve */}
                <path
                  className="dotted-path"
                  d="M 200 250 Q 300 150 200 50"
                />
              </svg>

              {/* Surrounding Small Images */}
              <div className="absolute inset-0 flex items-center justify-center">
                <AnimatePresence>
                  {surroundingImages.map((item, idx) => {
                    const angle = (idx * 60) * (Math.PI / 180);
                    const radius = 120;
                    const x = Math.cos(angle) * radius;
                    const y = Math.sin(angle) * radius;

                    return (
                      <motion.div
                        key={`${activeIndex}-${idx}`}
                        initial={{ opacity: 0, scale: 0 }}
                        animate={{ opacity: 0.6, scale: 1 }}
                        exit={{ opacity: 0, scale: 0 }}
                        transition={{ duration: 0.5 }}
                        style={{
                          position: 'absolute',
                          left: '50%',
                          top: '50%',
                          transform: `translate(calc(-50% + ${x}px), calc(-50% + ${y}px))`,
                        }}
                        className="w-16 h-16 md:w-20 md:h-20"
                      >
                        <motion.img
                          src={foodImages[item.index].image}
                          alt={foodImages[item.index].name}
                          className="w-full h-full rounded-full object-cover shadow-md border-2 border-white"
                          variants={smallImageVariants}
                          whileHover="hover"
                        />
                      </motion.div>
                    );
                  })}
                </AnimatePresence>
              </div>

              {/* Main Large Food Image */}
              <motion.div
                className="relative z-10 w-64 h-64 md:w-80 md:h-80"
                variants={floatingVariants}
                animate="animate"
              >
                <AnimatePresence mode="wait">
                  <motion.div
                    key={activeIndex}
                    variants={imageVariants}
                    initial="enter"
                    animate="center"
                    exit="exit"
                    className="absolute inset-0"
                  >
                    <motion.img
                      src={currentFood.image}
                      alt={currentFood.name}
                      className="w-full h-full rounded-full object-cover shadow-2xl border-4 border-white"
                      whileHover={{ scale: 1.05 }}
                    />
                    {/* Circular Background Glow */}
                    <div
                      className="absolute inset-0 rounded-full opacity-20 blur-2xl -z-10"
                      style={{ backgroundColor: currentFood.color }}
                    ></div>
                  </motion.div>
                </AnimatePresence>
              </motion.div>

              {/* Arrow Navigation Buttons */}
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.8 }}
                className="absolute right-0 top-1/2 transform -translate-y-1/2 flex flex-col gap-4 z-20"
              >
                {/* Up Arrow */}
                <motion.button
                  onClick={handlePrevious}
                  whileHover={{ scale: 1.1, backgroundColor: '#16a34a' }}
                  whileTap={{ scale: 0.95 }}
                  className="p-3 bg-green-600 text-white rounded-full shadow-lg hover:bg-green-700 transition-colors"
                  aria-label="Previous food item"
                >
                  <ChevronUp size={24} />
                </motion.button>

                {/* Down Arrow */}
                <motion.button
                  onClick={handleNext}
                  whileHover={{ scale: 1.1, backgroundColor: '#16a34a' }}
                  whileTap={{ scale: 0.95 }}
                  className="p-3 bg-green-600 text-white rounded-full shadow-lg hover:bg-green-700 transition-colors"
                  aria-label="Next food item"
                >
                  <ChevronDown size={24} />
                </motion.button>
              </motion.div>

              {/* Food Name Display */}
              <motion.div
                key={activeIndex}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                transition={{ duration: 0.4 }}
                className="absolute bottom-0 left-1/2 transform -translate-x-1/2 text-center"
              >
                <p className="text-lg font-bold text-gray-800">{currentFood.name}</p>
              </motion.div>
            </motion.div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default HeroSection;
